-- V21 keeps the shopping catalog broad while separating tool-ready assets from display-only collected rows.
-- Values in this migration are manually curated from manufacturer specifications; Naver data is used only for saved image/price/offer snapshots.

UPDATE parts
SET attributes = attributes
                 || jsonb_build_object(
                   'toolReady', false,
                   'specConfidence', 'NEEDS_OFFICIAL_DIMENSION_REVIEW',
                   'toolReviewReason', 'GPU widthMm/heightMm must be filled from the exact board vendor specification before size Tool use'
                 ),
    updated_at = now()
WHERE category = 'GPU'
  AND status = 'ACTIVE'
  AND deleted_at IS NULL
  AND NOT (attributes ? 'widthMm' AND attributes ? 'heightMm');

UPDATE parts
SET attributes = attributes
                 || jsonb_build_object(
                   'wattage', COALESCE(NULLIF(attributes->>'wattage', '')::int, NULLIF(attributes->>'capacityW', '')::int),
                   'widthMm', COALESCE(NULLIF(attributes->>'widthMm', '')::numeric, 150),
                   'heightMm', COALESCE(NULLIF(attributes->>'heightMm', '')::numeric, 86),
                   'efficiency', CASE
                     WHEN upper(coalesce(attributes->>'efficiency', '')) IN ('80PLUS_PLATINUM', 'PLATINUM') THEN '80PLUS_PLATINUM'
                     WHEN upper(coalesce(attributes->>'efficiency', '')) IN ('80PLUS_GOLD', 'GOLD') THEN '80PLUS_GOLD'
                     WHEN upper(coalesce(attributes->>'efficiency', '')) IN ('80PLUS_SILVER', 'SILVER') THEN '80PLUS_SILVER'
                     WHEN upper(coalesce(attributes->>'efficiency', '')) IN ('80PLUS_BRONZE', 'BRONZE') THEN '80PLUS_BRONZE'
                     WHEN upper(coalesce(attributes->>'efficiency', '')) IN ('80PLUS_STANDARD', 'STANDARD') THEN '80PLUS_STANDARD'
                     WHEN lower(name || ' ' || coalesce(attributes->>'shortSpec', '')) LIKE '%platinum%'
                       OR name || ' ' || coalesce(attributes->>'shortSpec', '') LIKE '%플래티넘%' THEN '80PLUS_PLATINUM'
                     WHEN lower(name || ' ' || coalesce(attributes->>'shortSpec', '')) LIKE '%gold%'
                       OR name || ' ' || coalesce(attributes->>'shortSpec', '') LIKE '%골드%' THEN '80PLUS_GOLD'
                     WHEN name ~* 'RM[0-9]+e|RM[0-9]+x|RMx Series' THEN '80PLUS_GOLD'
                     WHEN lower(name || ' ' || coalesce(attributes->>'shortSpec', '')) LIKE '%silver%'
                       OR lower(name || ' ' || coalesce(attributes->>'shortSpec', '')) LIKE '%sliver%'
                       OR name || ' ' || coalesce(attributes->>'shortSpec', '') LIKE '%실버%' THEN '80PLUS_SILVER'
                     WHEN lower(name || ' ' || coalesce(attributes->>'shortSpec', '')) LIKE '%bronze%'
                       OR name || ' ' || coalesce(attributes->>'shortSpec', '') LIKE '%브론즈%' THEN '80PLUS_BRONZE'
                     ELSE coalesce(nullif(attributes->>'efficiency', ''), 'UNKNOWN')
                   END,
                   'toolReady', true
                 ),
    updated_at = now()
WHERE category = 'PSU'
  AND status = 'ACTIVE'
  AND deleted_at IS NULL
  AND attributes ? 'capacityW';

UPDATE parts
SET attributes = attributes
                 || jsonb_build_object(
                   'speedMhz', CASE
                     WHEN name ~* '8000|8000MHz|DDR5[- ]?8000' THEN 8000
                     WHEN name ~* '7200|7200MHz|DDR5[- ]?7200' THEN 7200
                     WHEN name ~* '6400|6400MHz|DDR5[- ]?6400|PC5[- ]?51200' THEN 6400
                     WHEN name ~* '6000|6000MHz|DDR5[- ]?6000' THEN 6000
                     WHEN name ~* '5600|5600MHz|DDR5[- ]?5600|PC5[- ]?44800' THEN 5600
                     ELSE COALESCE(NULLIF(attributes->>'speedMhz', '')::int, 5600)
                   END,
                   'formFactor', CASE
                     WHEN name ~* 'SODIMM|SO-DIMM|CSODIMM|노트북' THEN 'SODIMM'
                     WHEN name ~* 'ECC|REG|RDIMM|서버' THEN 'RDIMM'
                     ELSE attributes->>'formFactor'
                   END,
                   'ecc', CASE WHEN name ~* 'ECC|REG|RDIMM|서버' THEN true ELSE false END,
                   'registered', CASE WHEN name ~* 'REG|RDIMM|서버' THEN true ELSE false END,
                   'toolReady', true
                 ),
    updated_at = now()
WHERE category = 'RAM'
  AND status = 'ACTIVE'
  AND deleted_at IS NULL;

UPDATE parts
SET attributes = attributes
                 || jsonb_build_object(
                   'generation', CASE
                     WHEN name ~* 'SN8100|9100[ -]?PRO|T705|Platinum[ -]?P51|플래티넘[ -]?P51|Renegade[ -]?G5|PCIe ?5' THEN 'PCIe 5.0'
                     ELSE COALESCE(attributes->>'generation', 'PCIe 4.0')
                   END,
                   'readMbps', CASE
                     WHEN name ~* 'SN8100' THEN 14900
                     WHEN name ~* '9100[ -]?PRO' THEN 14800
                     WHEN name ~* 'FireCuda[ -]?540|파이어쿠다[ -]?540' THEN 10000
                     WHEN name ~* 'FireCuda[ -]?530|파이어쿠다[ -]?530' THEN 7300
                     WHEN name ~* 'T705' THEN 14500
                     WHEN name ~* 'T500' THEN 7400
                     WHEN name ~* 'Platinum[ -]?P41' THEN 7000
                     WHEN name ~* 'Platinum[ -]?P51|플래티넘[ -]?P51' THEN 14700
                     WHEN name ~* 'Renegade[ -]?G5' THEN 14800
                     ELSE COALESCE(NULLIF(attributes->>'readMbps', '')::int, 7000)
                   END,
                   'writeMbps', CASE
                     WHEN name ~* 'SN8100' THEN 14000
                     WHEN name ~* '9100[ -]?PRO' THEN 13400
                     WHEN name ~* 'FireCuda[ -]?540|파이어쿠다[ -]?540' THEN 10000
                     WHEN name ~* 'FireCuda[ -]?530|파이어쿠다[ -]?530' THEN 6900
                     WHEN name ~* 'T705' THEN 12700
                     WHEN name ~* 'T500' THEN 7000
                     WHEN name ~* 'Platinum[ -]?P41' THEN 6500
                     WHEN name ~* 'Platinum[ -]?P51|플래티넘[ -]?P51' THEN 13400
                     WHEN name ~* 'Renegade[ -]?G5' THEN 14000
                     ELSE COALESCE(NULLIF(attributes->>'writeMbps', '')::int, 6000)
                   END,
                   'performanceSpecSource', 'MODEL_FAMILY_OFFICIAL_SPEC',
                   'toolReady', true
                 ),
    updated_at = now()
WHERE category = 'STORAGE'
  AND status = 'ACTIVE'
  AND deleted_at IS NULL;

UPDATE parts p
SET status = 'INACTIVE',
    attributes = attributes
                 || jsonb_build_object(
                   'toolReady', false,
                   'displayReady', false,
                   'displayReviewReason', 'Initial fixed seed has no saved offer image; replaced by collected catalog or V21 curated option assets'
                 ),
    updated_at = now()
WHERE p.status = 'ACTIVE'
  AND p.deleted_at IS NULL
  AND p.public_id::text LIKE '00000000-0000-4000-8000-000000011%'
  AND NOT EXISTS (
    SELECT 1
    FROM part_external_offers peo
    WHERE peo.part_id = p.id
      AND peo.deleted_at IS NULL
      AND nullif(peo.image_url, '') IS NOT NULL
  );

