    ('00000000-0000-4000-8000-000000013045', 'ARCTIC Liquid Freezer III 280', 'ARCTIC Liquid Freezer III PRO 280 서린 (블랙) CPU수냉쿨러', 'https://shopping-phinf.pstatic.net/main_8997329/89973297583.jpg', '더상상플랫폼', 'https://smartstore.naver.com/main/products/12428786836', 152000, '{"source":"naver-shopping-search","selectedFor":"00000000-0000-4000-8000-000000013045","sourceProductKey":"89973297583","maker":null,"brand":null,"officialSpecUrl":"https://www.arctic.de/en/Liquid-Freezer-III-280/ACFRE00135A","selectedAt":"2026-06-29"}'),
    ('00000000-0000-4000-8000-000000013046', 'NZXT Kraken 240', 'NZXT Kraken Core 240 RGB 블랙', 'https://shopping-phinf.pstatic.net/main_5828260/58282607634.20251226182048.jpg', '네이버', 'https://search.shopping.naver.com/catalog/58282607634', 99800, '{"source":"naver-shopping-search","selectedFor":"00000000-0000-4000-8000-000000013046","sourceProductKey":"58282607634","maker":"NZXT","brand":"NZXT","officialSpecUrl":"https://nzxt.com/product/kraken-240","selectedAt":"2026-06-29"}')
), matched_parts AS (
  SELECT p.id AS part_id, s.search_query, s.title, s.image_url, s.supplier_name, s.offer_url, s.low_price, s.raw_payload
  FROM seed_offers s
  JOIN parts p ON p.public_id = s.public_id::uuid
  WHERE p.deleted_at IS NULL
), upserted_offers AS (
  INSERT INTO part_external_offers (
    part_id, source, search_query, title, image_url, supplier_name, offer_url, low_price, raw_payload, refreshed_at, created_at, updated_at
  )
  SELECT part_id, 'NAVER_SHOPPING_SEARCH', search_query, title, image_url, supplier_name, offer_url, low_price, raw_payload::jsonb, '2026-06-29T19:40:00Z', now(), now()
  FROM matched_parts
  ON CONFLICT (part_id, source) WHERE deleted_at IS NULL DO UPDATE SET
    search_query = EXCLUDED.search_query,
    title = EXCLUDED.title,
    image_url = EXCLUDED.image_url,
    supplier_name = EXCLUDED.supplier_name,
    offer_url = EXCLUDED.offer_url,
    low_price = EXCLUDED.low_price,
    raw_payload = EXCLUDED.raw_payload,
    refreshed_at = EXCLUDED.refreshed_at,
    updated_at = now()
  RETURNING part_id, low_price
)
UPDATE parts p
SET price = u.low_price, updated_at = now()
FROM upserted_offers u
WHERE p.id = u.part_id
  AND u.low_price > 0;

INSERT INTO price_snapshots (part_id, price, source, collected_at)
SELECT p.id, peo.low_price, peo.source, peo.refreshed_at
FROM parts p
JOIN part_external_offers peo ON peo.part_id = p.id AND peo.source = 'NAVER_SHOPPING_SEARCH' AND peo.deleted_at IS NULL
